func scaleDisplay(ms int, scale string) string {
	switch scale {
	case "ms":
		return fmt.Sprintf("%d", ms)
	case "s":
		return fmt.Sprintf("%d", ms/1000)
	case "min":
		return fmt.Sprintf("%d", ms/60000)
	case "h":
		return fmt.Sprintf("%d", ms/3600000)
	default:
		return fmt.Sprintf("%d", ms/1000)
	}
}

func pinTitle(pinned bool) string {
	if pinned {
		return "Pinned — master control will not override this section"
	}
	return "Pin to prevent master override"
}

func scaleAttr(scale, attr string) string {
	type cfg struct{ min, max, step string }
	scales := map[string]cfg{
		"ms":  {"100", "900", "100"},
		"s":   {"1", "59", "1"},
		"min": {"1", "59", "1"},
		"h":   {"1", "24", "1"},
	}
	c, ok := scales[scale]
	if !ok {
		c = scales["s"]
	}
	switch attr {
	case "min":
		return c.min
	case "max":
		return c.max
	case "step":
		return c.step
	default:
		return "1"
	}
}

